from __future__ import annotations

import struct
from dataclasses import dataclass


def f64(bits: int) -> float:
    return struct.unpack(">d", struct.pack(">Q", bits))[0]


def f64_bits(values: list[float]) -> list[int]:
    return [struct.unpack(">Q", struct.pack(">d", value))[0] for value in values]


def assert_f64_bits_equal(actual: list[float], expected: list[float]) -> None:
    assert f64_bits(actual) == f64_bits(expected)


@dataclass(frozen=True)
class VectorCase:
    name: str
    values: list[float]
    encoded_hex: dict[str, str]

    def encoded_bytes(self, algorithm: str) -> bytes:
        return bytes.fromhex(self.encoded_hex[algorithm])


